import React, { useEffect } from 'react';
import { Typography, Button } from '@mui/material';
import { Link, useParams } from 'react-router-dom';
import fetchModel from '../../modelData/models';

const UserDetail = ({ setContext }) => {
  const { userId } = useParams(); 
  const user = fetchModel.userModel(userId);

  // useEffect sẽ chạy mỗi khi user thay đổi để cập nhật TopBar
  useEffect(() => {
    if (user) {
      setContext(`${user.first_name} ${user.last_name}`);
    }
  }, [user, setContext]);

  if (!user) return <div>User not found!</div>;

  return (
    <div>
      <Typography variant="h4">{user.first_name} {user.last_name}</Typography>
      <Typography variant="subtitle1">Location: {user.location}</Typography>
      <Typography variant="subtitle1">Occupation: {user.occupation}</Typography>
      <Typography variant="body1">Description: {user.description}</Typography>

      <br />
      {/* Nút chuyển sang trang xem ảnh */}
      <Button variant="contained" component={Link} to={`/photos/${user._id}`}>
        View Photos
      </Button>
    </div>
  );
};

export default UserDetail;
